ee:message.ee:set-payload:
%dw 2.0
output application/json
var resultBody = payload.result default {}
var isError = (payload.status default "") == "error"
---
{ jsonrpc: "2.0", id: vars.rpcId, result: { content: [{ "type": "text", text: write(resultBody, "application/json") }], isError: isError } }

%dw 2.0
output application/json
---
{
  tools: [
    {
      name: "get_alternative_parts",
      description: "代替部品候補を IDMC KG から取得する。互換スコア降順で返す。",
      inputSchema: {
        "type": "object",
        properties: { partNumber: { "type": "string" } },
        required: ["partNumber"]
      }
    },
    {
      name: "create_purchase_order_draft",
      description: "代替発注書ドラフトを生成する。Status=DRAFT で挿入し autonumber を draftId として返す。",
      inputSchema: {
        "type": "object",
        properties: {
          partNumber:       { "type": "string" },
          quantity:         { "type": "integer" },
          supplierGoldenId: { "type": "string" },
          incidentId:       { "type": "string" },
          unitPrice:        { "type": "number" },
          notes:            { "type": "string" }
        },
        required: ["partNumber", "quantity", "supplierGoldenId"]
      }
    },
    {
      name: "notify_supplier",
      description: "サプライヤーへの連絡をキューする。発注・キャンセル・情報の 3 種別。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          "type":           { "type": "string", "enum": ["ORDER", "CANCEL", "INFO"] },
          message:          { "type": "string" },
          incidentId:       { "type": "string" }
        },
        required: ["supplierGoldenId", "type", "message"]
      }
    }
  ]
}

